import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';

// Importando os SVGs
import bitcoinLogo from '../../assets/crypto_logos/bitcoin.svg';
import ethereumLogo from '../../assets/crypto_logos/ethereum.svg';
import litecoinLogo from '../../assets/crypto_logos/litecoin.svg';
import rippleLogo from '../../assets/crypto_logos/ripple.svg';
import cardanoLogo from '../../assets/crypto_logos/cardano.svg';
import polkadotLogo from '../../assets/crypto_logos/polkadot.svg';
import chainlinkLogo from '../../assets/crypto_logos/chainlink.svg';
import binanceLogo from '../../assets/crypto_logos/binance.svg';
import solanaLogo from '../../assets/crypto_logos/solana.svg';
import dogecoinLogo from '../../assets/crypto_logos/dogecoin.svg';
// Adicione mais importações de logos conforme necessário

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [displayText, setDisplayText] = useState('');
  const [isTyping, setIsTyping] = useState(true);
  const [showDots, setShowDots] = useState(false);

  const fullText = 'Nautilus Automação';
  const typingSpeed = 150;
  const pauseTime = 10000;

  // Array de logos SVG importados
  const cryptoLogos = [
    bitcoinLogo,
    ethereumLogo,
    litecoinLogo,
    rippleLogo,
    cardanoLogo,
    polkadotLogo,
    chainlinkLogo,
    binanceLogo,
    solanaLogo,
    dogecoinLogo,
    // Adicione mais variáveis de logos importados aqui
  ];

  // Array extenso de símbolos de criptomoedas e blockchain
  const cryptoSymbols = [
    // Símbolos principais de criptomoedas
    '₿', 'Ξ', '⟠', 'Ł', '◊', '⧫', '◈', '◇', '⬟', '⬢', '⬡', '⬠',
    // Símbolos matemáticos e geométricos relacionados
    '⟐', '⟡', '⟢', '⟣', '⟤', '⟥', '⟦', '⟧', '⟨', '⟩', '⟪', '⟫', '⟬', '⟭',
    // Símbolos de moedas e financeiros
    '¤', '₳', '₴', '₵', '₶', '₷', '₸', '₹', '₺', '₻', '₼', '₽', '₾', '₿',
    // Símbolos de blockchain e tecnologia
    '⬢', '⬡', '⬠', '⬟', '⬞', '⬝', '⬜', '⬛', '⭐', '⭑', '⭒', '⭓', '⭔', '⭕',
    // Símbolos geométricos avançados
    '◆', '◇', '◈', '◉', '◊', '○', '◌', '◍', '◎', '●', '◐', '◑', '◒', '◓',
    // Símbolos de setas e direcionais
    '↗', '↘', '↙', '↖', '↕', '↔', '⇄', '⇅', '⇆', '⇇', '⇈', '⇉', '⇊', '⇋',
    // Símbolos de estrelas e formas
    '★', '☆', '✦', '✧', '✩', '✪', '✫', '✬', '✭', '✮', '✯', '✰', '✱', '✲',
    // Símbolos de tecnologia e digital
    '⚡', '⚙', '⚛', '⚜', '⚝', '⚞', '⚟', '⚠', '⚡', '⚢', '⚣', '⚤', '⚥', '⚦',
    // Símbolos adicionais de criptomoedas conhecidas
    'Ð', 'Ł', 'Ξ', '₳', 'Ⱥ', 'Ƀ', 'Ȼ', 'Đ', 'Ɇ', 'Ƒ', 'Ǥ', 'Ħ', 'Ɨ', 'Ɉ',
    // Símbolos de redes e conexões
    '⌘', '⌬', '⌭', '⌮', '⌯', '⌰', '⌱', '⌲', '⌳', '⌴', '⌵', '⌶', '⌷', '⌸',
    // Símbolos de segurança e criptografia
    '🔐', '🔑', '🔒', '🔓', '🔔', '🔕', '🔖', '🔗', '🔘', '🔙', '🔚', '🔛', '🔜', '🔝',
    // Símbolos de gráficos e análise
    '📈', '📉', '📊', '📋', '📌', '📍', '📎', '📏', '📐', '📑', '📒', '📓', '📔', '📕'
  ];

  useEffect(() => {
    let timeoutId;
    let currentIndex = 0;

    const typeText = () => {
      if (currentIndex <= fullText.length) {
        setDisplayText(fullText.slice(0, currentIndex));
        currentIndex++;
        timeoutId = setTimeout(typeText, typingSpeed);
      } else {
        setIsTyping(false);
        setShowDots(true);
        timeoutId = setTimeout(() => {
          setShowDots(false);
          setIsTyping(true);
          setDisplayText('');
          currentIndex = 0;
          typeText();
        }, pauseTime);
      }
    };

    typeText();

    return () => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
    };
  }, []);

  // Removido - não precisamos mais da animação de fundo

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Limpar erro quando o usuário começar a digitar
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Validação básica
    if (!formData.email || !formData.password) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    // Validação simples de email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    try {
      const result = await login(formData.email, formData.password);

      if (result.success) {
        toast.success('Login realizado com sucesso!');
      } else {
        setError(result.message || 'Erro ao fazer login');
        toast.error(result.message || 'Erro ao fazer login');
      }
    } catch (error) {
      console.error('Erro no login:', error);
      setError('Erro ao fazer login. Tente novamente.');
      toast.error('Erro ao fazer login');
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        background: '#000000', // Fundo preto
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2
      }}
    >
      {/* CSS para animações */}
      <style>
        {`
          @keyframes blink {
            0%, 50% { opacity: 1; }
            51%, 100% { opacity: 0; }
          }
          @keyframes blinkDots {
            0%, 33% { opacity: 1; }
            34%, 66% { opacity: 0.5; }
            67%, 100% { opacity: 0; }
          }
          @keyframes shimmer {
            0% {
              background-position: -200% 0;
            }
            100% {
              background-position: 200% 0;
            }
          }
        `}
      </style>

      {/* Cartão de Crédito */}
      <Box
        sx={{
          width: '100%',
          maxWidth: 450,
          height: 280,
          background: 'linear-gradient(135deg, rgba(192, 192, 192, 0.1) 0%, rgba(169, 169, 169, 0.05) 100%)',
          borderRadius: '20px',
          border: '1px solid rgba(192, 192, 192, 0.3)',
          backdropFilter: 'blur(20px)',
          position: 'relative',
          overflow: 'hidden',
          boxShadow: '0 8px 32px rgba(0, 0, 0, 0.3), inset 0 1px 0 rgba(255, 255, 255, 0.1)',
          '&::before': {
            content: '""',
            position: 'absolute',
            top: 0,
            left: '-100%',
            width: '100%',
            height: '100%',
            background: 'linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.1), transparent)',
            animation: 'shimmer 3s infinite'
          }
        }}
      >
        {/* Chip do cartão */}
        <Box
          sx={{
            position: 'absolute',
            top: 30,
            left: 30,
            width: 40,
            height: 30,
            background: 'linear-gradient(135deg, #C0C0C0, #A9A9A9)',
            borderRadius: '4px',
            border: '1px solid rgba(192, 192, 192, 0.5)'
          }}
        />

        {/* Logo/Marca */}
        <Box
          sx={{
            position: 'absolute',
            top: 30,
            right: 30,
            color: '#C0C0C0',
            fontSize: '18px',
            fontWeight: 'bold',
            fontFamily: 'monospace'
          }}
        >
          BIT NOVA
        </Box>

        {/* Área do formulário */}
        <Box
          sx={{
            position: 'absolute',
            bottom: 0,
            left: 0,
            right: 0,
            padding: 3,
            background: 'rgba(0, 0, 0, 0.2)',
            borderTop: '1px solid rgba(192, 192, 192, 0.2)'
          }}
        >
          <Box component="form" onSubmit={handleSubmit}>
            {/* Título do cartão */}
            <Box sx={{ textAlign: 'center', mb: 2 }}>
              <Typography
                variant="h6"
                component="h1"
                sx={{
                  fontWeight: 'bold',
                  color: '#C0C0C0',
                  mb: 0.5,
                  fontSize: '1rem',
                  textTransform: 'uppercase',
                  letterSpacing: '1px'
                }}
              >
                ACESSO SEGURO
              </Typography>
            </Box>
              {error && (
                <Alert 
                  severity="error" 
                  sx={{ 
                    mb: 2,
                    backgroundColor: 'rgba(211, 47, 47, 0.1)',
                    color: '#ff6b6b',
                    border: '1px solid rgba(211, 47, 47, 0.3)',
                    '& .MuiAlert-icon': {
                      color: '#ff6b6b'
                    }
                  }}
                >
                  {error}
                </Alert>
              )}

              <TextField
                fullWidth
                name="email"
                label="USUÁRIO"
                type="email"
                value={formData.email}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="email"
                autoFocus
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Email sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: 'rgba(192, 192, 192, 0.05)',
                    border: '1px solid rgba(192, 192, 192, 0.3)',
                    borderRadius: '8px',
                    color: '#C0C0C0',
                    '& fieldset': {
                      border: 'none'
                    },
                    '&:hover': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid rgba(192, 192, 192, 0.5)'
                    },
                    '&.Mui-focused': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid #C0C0C0'
                    }
                  },
                  '& .MuiInputLabel-root': {
                    color: '#A9A9A9',
                    fontSize: '0.75rem',
                    fontWeight: 'bold',
                    letterSpacing: '1px'
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#C0C0C0'
                  }
                }}
              />

              <TextField
                fullWidth
                name="password"
                label="SENHA"
                type={showPassword ? 'text' : 'password'}
                value={formData.password}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="current-password"
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Lock sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={togglePasswordVisibility}
                        edge="end"
                        aria-label="toggle password visibility"
                        sx={{ color: '#C0C0C0' }}
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: 'rgba(192, 192, 192, 0.05)',
                    border: '1px solid rgba(192, 192, 192, 0.3)',
                    borderRadius: '8px',
                    color: '#C0C0C0',
                    '& fieldset': {
                      border: 'none'
                    },
                    '&:hover': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid rgba(192, 192, 192, 0.5)'
                    },
                    '&.Mui-focused': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid #C0C0C0'
                    }
                  },
                  '& .MuiInputLabel-root': {
                    color: '#A9A9A9',
                    fontSize: '0.75rem',
                    fontWeight: 'bold',
                    letterSpacing: '1px'
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#C0C0C0'
                  }
                }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                disabled={loading}
                sx={{
                  mt: 2,
                  mb: 1,
                  py: 1,
                  fontSize: '0.875rem',
                  fontWeight: 'bold',
                  textTransform: 'uppercase',
                  letterSpacing: '1px',
                  background: 'linear-gradient(135deg, rgba(192, 192, 192, 0.2), rgba(169, 169, 169, 0.1))',
                  color: '#C0C0C0',
                  border: '1px solid rgba(192, 192, 192, 0.3)',
                  borderRadius: '8px',
                  backdropFilter: 'blur(10px)',
                  '&:hover': {
                    background: 'linear-gradient(135deg, rgba(192, 192, 192, 0.3), rgba(169, 169, 169, 0.2))',
                    border: '1px solid rgba(192, 192, 192, 0.5)',
                  },
                  '&:disabled': {
                    background: 'rgba(192, 192, 192, 0.05)',
                    color: 'rgba(192, 192, 192, 0.3)',
                  },
                }}
              >
                {loading ? (
                  <CircularProgress size={20} sx={{ color: '#C0C0C0' }} />
                ) : (
                  'ENTRAR'
                )}
              </Button>

              {/* Link para registro */}
              <Box sx={{ textAlign: 'center', mt: 1 }}>
                <Typography 
                  variant="body2" 
                  sx={{ 
                    color: '#A9A9A9',
                    fontSize: '0.75rem'
                  }}
                >
                  Não tem conta?{' '}
                  <Link
                    component={RouterLink}
                    to="/register"
                    sx={{
                      color: '#C0C0C0',
                      textDecoration: 'none',
                      fontWeight: 'bold',
                      fontSize: '0.75rem',
                      '&:hover': {
                        textDecoration: 'underline',
                        color: '#DCDCDC'
                      },
                    }}
                  >
                    REGISTRE-SE
                  </Link>
                </Typography>
              </Box>
            </Box>
          </Box>
        </Box>
      </Box>
  );
};

export default Login;
